using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary (default: 3).
    /// </summary>
    [Range(1, 100)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using DocSummary.Models;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    SummarizeResponse Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by word frequency
/// and returns the top-ranked ones in their original order.
/// </summary>
public partial class ExtractiveSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","is","are","was","were","be","been","being",
        "have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","am","it","its",
        "in","on","at","to","for","of","with","by","from","as","into",
        "through","during","before","after","above","below","between",
        "out","off","over","under","again","further","then","once",
        "and","but","or","nor","not","so","yet","both","either",
        "neither","each","every","all","any","few","more","most",
        "other","some","such","no","only","own","same","than","too",
        "very","just","because","if","when","where","how","what",
        "which","who","whom","this","that","these","those","i","me",
        "my","myself","we","our","ours","ourselves","you","your",
        "yours","yourself","yourselves","he","him","his","himself",
        "she","her","hers","herself","they","them","their","theirs",
        "themselves"
    };

    public SummarizeResponse Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count == 0)
        {
            return new SummarizeResponse
            {
                Summary = string.Empty,
                OriginalSentenceCount = 0,
                SummarySentenceCount = 0
            };
        }

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((sentence, index) => (Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => sentences[s.Index])
            .ToList();

        return new SummarizeResponse
        {
            Summary = string.Join(" ", scored),
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = scored.Count
        };
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word))
                {
                    freq[word] = freq.TryGetValue(word, out var count) ? count + 1 : 1;
                }
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = Tokenize(sentence);
        if (words.Count == 0) return 0;

        double score = 0;
        foreach (var word in words)
        {
            if (wordFrequencies.TryGetValue(word, out var freq))
                score += freq;
        }

        // Normalize by word count to avoid bias toward long sentences
        return score / words.Count;
    }

    private static List<string> Tokenize(string text)
    {
        return WordTokenizer()
            .Matches(text)
            .Select(m => m.Value.ToLowerInvariant())
            .Where(w => w.Length > 1)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z0-9]+\b", RegexOptions.Compiled)]
    private static partial Regex WordTokenizer();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var result = _summarizer.Summarize(request.DocumentText, request.MaxSentences);
        return Ok(result);
    }
}

